import {Component, OnInit} from '@angular/core';
import {ActivatedRoute} from '@angular/router';
import {News} from '../../shared/api/dto/news';
import {NewsApiService} from '../../shared/api/news/news-api.service';

@Component({
  selector: 'app-news-details',
  templateUrl: './news-details.component.html',
  styleUrls: ['./news-details.component.sass']
})
export class NewsDetailsComponent implements OnInit {
  newsSingle: News;

  constructor(
    private activatedRoute: ActivatedRoute,
    private newsApiService: NewsApiService
  ) {
  }

  ngOnInit(): void {
    this.initPage();
  }

  initPage(): void {
    this.activatedRoute.params.subscribe(newsId => {
      this.newsApiService.newsSingle(newsId.id).subscribe(news => {
        this.newsSingle = news;
      });
    });
  }

}
